#!/usr/bin/env python3
"""Property-based tests for dedup.py — generated by forge.py --gen-props"""
import sys
import os
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from hypothesis import given, strategies as st, settings
from engine.core.dedup import *

@given(text=st.text(max_size=100), bits=st.integers(-1000, 1000), shingle_size=st.integers(-1000, 1000))
@settings(max_examples=50)
def test_simhash_no_crash(text, bits, shingle_size):
    """Smoke: simhash() does not crash on arbitrary input"""
    # from engine.core.dedup import simhash
    try:
        simhash(text, bits, shingle_size)
    except (ValueError, TypeError, KeyError, IndexError):
        pass  # Expected rejections are OK

